var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"PIRATE_FRONTBAY_NULL_SEVERAL2","text":{"KOREA":"크헤헤, 저항해도 소용없다고.","JPN":"クヘヘ、抵抗しても無駄だ。","ENG":"Ke he he, no use resisting.","TWN":"嘿嘿嘿，反抗也沒用。"},"stage":{"bg":"FRONTBAY_DECK","slots":{"L":{"char_id":"PIRATE_FRONTBAY_NULL_SEVERAL2","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L3_1","type":"dialog","speaker":"HUNTER_FRONTBAY_NULL_WATCH","text":{"KOREA":"끈질기군. 그런 실력들로 강도질이나 하는 게 아깝지도 않나?","JPN":"しつこいな。そんな腕で強盗をやっていて惜しいと思わないのか？","ENG":"How persistent. You could be using your strength to do something better than robbery, you know.","TWN":"真難纏，身手這麼好來當海盜不是很可惜嗎？"},"stage":{"bg":"FRONTBAY_DECK","slots":{"L":{"char_id":"PIRATE_FRONTBAY_NULL_SEVERAL2","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HUNTER_FRONTBAY_NULL_WATCH","face":"UNIT_IDLE"}}}},{"id":"L4_1","type":"dialog","speaker":"PIRATE_FRONTBAY_NULL_SEVERAL2","text":{"KOREA":"바다를 해치는 관리국의 개들을 내쫓는 게 우리 역할이거든.","JPN":"海を荒らす管理局の犬を追い払うのが俺たちの役目だ。","ENG":"Well, it's our job to give the boot to the Administration's dogs who are harming the ocean.","TWN":"誰叫我們的責任就是把危害大海的管理局走狗趕走。"},"stage":{"bg":"FRONTBAY_DECK","slots":{"L":{"char_id":"PIRATE_FRONTBAY_NULL_SEVERAL2","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"HUNTER_FRONTBAY_NULL_WATCH","face":"UNIT_IDLE"}}}},{"id":"L5_1","type":"dialog","speaker":"PIRATE_FRONTBAY_NULL_SEVERAL2","text":{"KOREA":"자, 무료로 바다를 위해 봉사하는 우리에게 순순히 환경보호비를 바치시지!","JPN":"さぁ、海のために無料でご奉仕している俺らに大人しく環境保護費を払うんだな！","ENG":"Now, why don't you surrender your donations to help save the environment to the people who are volunteering to clean the ocean?!","TWN":"我們可是自願免費守護這片大海，你就付一點環境保護費吧！"},"stage":{"bg":"FRONTBAY_DECK","slots":{"L":{"char_id":"PIRATE_FRONTBAY_NULL_SEVERAL2","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"HUNTER_FRONTBAY_NULL_WATCH","face":"UNIT_IDLE"}}}},{"id":"L7_1","type":"dialog","speaker":"DIGGER_FRONTBAY_NULL_NULL","text":{"KOREA":"이, 이봐! 채굴기가 부서지겠어! 빨리 저 녀석들 좀 어떻게 해보라고!","JPN":"お、おい！　採掘機が壊れてしまう！　あいつらを早く何とかしろ！","ENG":"H-hey! The excavator's going to break! Do something about them!","TWN":"喂！！採礦機會壞掉的！快想辦法解決他們！"},"stage":{"bg":"FRONTBAY_DECK","slots":{"L":null,"C":null,"R":null}}},{"id":"L8_1","type":"dialog","speaker":"HUNTER_FRONTBAY_NULL_WATCH","text":{"KOREA":"쳇, 기다려. 애초에 우리가 가져온 건 대 침식탄이라고.","JPN":"ちっ、待て。そもそも俺たちが持ってきたのは対侵食弾だ。","ENG":"Tch, hang on. We brought anti-C.O. bullets only.","TWN":"嘖，先等一下，我們帶來的子彈都是專門對付侵蝕體的。"},"stage":{"bg":"FRONTBAY_DECK","slots":{"L":null,"C":{"char_id":"HUNTER_FRONTBAY_NULL_WATCH","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"HUNTER_FRONTBAY_NULL_WATCH","text":{"KOREA":"이렇게 된 이상 놈들이 타고 온 배를 노려야…","JPN":"こうなった以上やつらが乗ってきた船を狙うしか……","ENG":"So we're going to have to aim for the ship they brought here...","TWN":"現在只能瞄準他們搭的船…"},"stage":{"bg":"FRONTBAY_DECK","slots":{"L":null,"C":{"char_id":"HUNTER_FRONTBAY_NULL_WATCH","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"HUNTER_FRONTBAY_NULL_WATCH","text":{"KOREA":"…음?","JPN":"……ん？","ENG":"...Mm?","TWN":"…嗯？"},"stage":{"bg":"FRONTBAY_DECK","slots":{"L":null,"C":{"char_id":"HUNTER_FRONTBAY_NULL_WATCH","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"PIRATE_FRONTBAY_NULL_SEVERAL","text":{"KOREA":"어엉?","JPN":"ああん？","ENG":"Huh?","TWN":"嗯？"},"stage":{"bg":"FRONTBAY_DECK","slots":{"L":null,"C":{"char_id":"PIRATE_FRONTBAY_NULL_SEVERAL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"DIGGER_FRONTBAY_NULL_NULL","text":{"KOREA":"총성이 멈췄어. 해적놈들의 탄약이 떨어졌군. 빨리 반격하라고!","JPN":"銃声が止まった。海賊どもの弾丸が切れたようだ。早く反撃しろ！","ENG":"The shooting stopped. They're out of ammo. Shoot back, now!","TWN":"槍聲停了，他們的子彈用完了嗎？快趁現在反擊！"},"stage":{"bg":"FRONTBAY_DECK","slots":{"L":null,"C":null,"R":null}}},{"id":"L15_1","type":"dialog","speaker":"HUNTER_FRONTBAY_NULL_WATCH","text":{"KOREA":"쉿, 소리를 들어봐.","JPN":"しっ、音を聞いてみろ。","ENG":"Shh. Listen.","TWN":"噓，你聽。"},"stage":{"bg":"FRONTBAY_DECK","slots":{"L":null,"C":{"char_id":"HUNTER_FRONTBAY_NULL_WATCH","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"DIGGER_FRONTBAY_NULL_NULL","text":{"KOREA":"바다가… 울고 있어?","JPN":"海が……泣いている？","ENG":"The ocean is... crying?","TWN":"大海…在哭？"},"stage":{"bg":"FRONTBAY_DECK","slots":{"L":null,"C":{"char_id":"HUNTER_FRONTBAY_NULL_WATCH","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"DIGGER_FRONTBAY_NULL_NULL","text":{"KOREA":"어떻게 된 거야?","JPN":"どういうこと？","ENG":"What's happening?","TWN":"怎麼會這樣？"},"stage":{"bg":"FRONTBAY_DECK","slots":{"L":null,"C":{"char_id":"HUNTER_FRONTBAY_NULL_WATCH","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"HUNTER_FRONTBAY_NULL_WATCH","text":{"KOREA":"이럴 리가. 아직 시기가 아닐 텐데?","JPN":"バカな。まだそんな時期じゃないはずだよな？","ENG":"No. It shouldn't be happening already...","TWN":"怎麼可能？時候不是還沒到嗎？"},"stage":{"bg":"FRONTBAY_DECK","slots":{"L":null,"C":{"char_id":"HUNTER_FRONTBAY_NULL_WATCH","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"DIGGER_FRONTBAY_NULL_NULL","text":{"KOREA":"뭐야? 해적놈들이 갑자기 돌아가잖아?","JPN":"何だ？　海賊どもがいきなり帰っている？","ENG":"What? The pirates are turning back!","TWN":"怎麼搞的？那些海盜掉頭了？"},"stage":{"bg":"FRONTBAY_DECK","slots":{"L":null,"C":{"char_id":"HUNTER_FRONTBAY_NULL_WATCH","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"HUNTER_FRONTBAY_NULL_WATCH","text":{"KOREA":"…우리도 철수해야 해! 당장!","JPN":"……俺たちも撤収するんだ！　今すぐ！","ENG":"...We need to leave! NOW!","TWN":"…我們也必須立刻離開！快！"},"stage":{"bg":"FRONTBAY_DECK","slots":{"L":null,"C":{"char_id":"HUNTER_FRONTBAY_NULL_WATCH","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"DIGGER_FRONTBAY_NULL_NULL","text":{"KOREA":"뭐? 그건 안돼. 아직 채굴기도 회수하지 못했다고!","JPN":"は？　それはダメだ。まだ採掘機も回収していないんだ！","ENG":"What? No. We haven't even retrieved the excavator yet!","TWN":"什麼？那怎麼行，採礦機都還沒回收欸！"},"stage":{"bg":"FRONTBAY_DECK","slots":{"L":null,"C":{"char_id":"HUNTER_FRONTBAY_NULL_WATCH","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"HUNTER_FRONTBAY_NULL_WATCH","text":{"KOREA":"지금은 그런 걸 신경 쓸 때가…!","JPN":"今はそんなことを気にする場合じゃ……！","ENG":"That's not what's important–!","TWN":"現在沒時間管這麼多了…！"},"stage":{"bg":"FRONTBAY_DECK","slots":{"L":null,"C":{"char_id":"HUNTER_FRONTBAY_NULL_WATCH","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"DIGGER_FRONTBAY_NULL_NULL","text":{"KOREA":"내… 채굴기가 바닷속으로 순식간에 잠겼어?!","JPN":"俺の……採掘機が一瞬に海の中に消えた！？","ENG":"My... excavator was just dragged underwater!","TWN":"我的… 採礦機瞬間沉到海裡了？！"},"stage":{"bg":"FRONTBAY_DECK","slots":{"L":null,"C":null,"R":null}}}]`);export{e as default};